360	func (t *Tunnel) stopMetricsLocked() {
361		if t.metricsSrv == nil {
362			return
363		}
364		ctx, cancel := context.WithTimeout(context.Background(), metricsShutdownTimeout)
365		defer cancel()
366		if err := t.metricsSrv.Close(ctx); err != nil {
367			t.log.Warn("metrics endpoint shutdown error", "error", err.Error())
368		}
369		t.metricsSrv = nil
370		t.metricsListen = ""
371	}
372	
373	// Reload applies a reloaded configuration to the RUNNING tunnel by diffing its
374	// path set against the live one and adding/removing paths at runtime (T30), WITHOUT
375	// tearing the tunnel down: the WG session, the surviving paths, and in-flight
376	// resequencing are all preserved. cfg is assumed already validated (config.Load
377	// fails fast on a bad file, so a bad reload never reaches here and never disturbs
378	// the running tunnel). Only the path set is diffed — the crypto/amnezia/role fields
379	// are fixed for the life of the process and a reload does not re-key the engine.
